      link.delete if link.symlink? || link.exist?
      link.make_symlink("pmx")
    end
  end

  uninstall_postflight do
    %w[pve pbs pdm].each do |persona|
      link = HOMEBREW_PREFIX/"bin"/persona
      link.delete if link.symlink?
    end
  end

